describe('pull function with 3 arguments', () => {
  it('should correctly handle the case with 3 arguments', () => {
    const mockRead = jest.fn();
    const mockSink = jest.fn();
    const mockSource = jest.fn(() => mockRead);

    const stream = {
      sink: mockSink,
      source: mockSource
